#!/usr/bin/env bash
# Generated by DaGhE Orchestrator - Ephemeral Tunnel Management
set -euo pipefail

# 1. Environment Discovery
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
export BASE_DIR="$(cd "${SCRIPT_DIR}/../.." && pwd)"

# 2. Proxy Initialization
PROXY_NAME=""
TUNNEL_PID=""

# Cleanup function to ensure the tunnel is killed on exit
cleanup() {
    if [[ -n "$TUNNEL_PID" ]]; then
        echo "[$(date)] daghe-youtube-ia-archiver: Shutting down proxy tunnel (PID: $TUNNEL_PID)..."
        kill "$TUNNEL_PID" 2>/dev/null || true
    fi
}
trap cleanup EXIT

if [[ -n "$PROXY_NAME" ]]; then
    PROXY_FILE="${BASE_DIR}/config/proxies/${PROXY_NAME}.env"
    if [[ -f "$PROXY_FILE" ]]; then
        source "$PROXY_FILE"
        echo "[$(date)] daghe-youtube-ia-archiver: Starting ephemeral tunnel: $PROXY_NAME"

        # Start the tunnel in the background
        ${PROXY_CMD} &
        TUNNEL_PID=$!

        # Wait for the local port to become active (timeout after 15 seconds)
        MAX_RETRIES=15
        COUNT=0
        while ! ss -lnt | grep -q ":${PROXY_LOCAL_PORT} "; do
            sleep 1
            ((COUNT++))
            if [[ $COUNT -ge $MAX_RETRIES ]]; then
                echo "[$(date)] daghe-youtube-ia-archiver: ERROR: Tunnel failed to initialise on port ${PROXY_LOCAL_PORT}"
                exit 1
            fi
        done
        echo "[$(date)] daghe-youtube-ia-archiver: Tunnel ready on port ${PROXY_LOCAL_PORT}"
    else
        echo "[$(date)] daghe-youtube-ia-archiver: ERROR: Proxy config $PROXY_FILE missing."
        exit 1
    fi
fi

# 3. Locking & Execution
LOCK_FILE="${BASE_DIR}/state/daghe-youtube-ia-archiver.lock"
exec 9>"$LOCK_FILE"
if ! flock -n 9; then
    echo "[$(date)] daghe-youtube-ia-archiver: Already running, skipping."
    exit 0
fi

cd "${BASE_DIR}/jobs/daghe-youtube-ia-archiver/current"
export PYTHONPATH="src"

# Execute the module
uv run python -m youtube_ia_archiver.cli --config config/job.yaml
